<template>
  <!-- Assume that the header is already included via BaseLayout -->
  <v-container fluid>
    <v-row justify="center">
      <v-col cols="12" sm="8" md="6">
        <v-card class="pa-5" color="blue-grey-lighten-3">
          <v-card-title>Choose an Option</v-card-title>
          <v-card-text>
            <v-select
              v-model="selectedTemplate"
              :items="templates"
              item-title="label"
              item-value="fileId" 
              label="Select a Document Template"
              return-object
            ></v-select>

            <v-btn
              color="blue-grey-darken-4"
              class="ma-3"
              @click="navigateToInputFieldsPage"
              :disabled="!selectedTemplate"
            >
              Go to Input Fields Page
            </v-btn>
          </v-card-text>
        </v-card>
      </v-col>
    </v-row>
  </v-container>
</template>

<script>
import { ref, onMounted, defineComponent, watch } from 'vue';
import { useRouter } from 'vue-router';
import axios from 'axios';
import { useStore } from 'vuex';

export default defineComponent({
  setup() {
    const router = useRouter();
    const store = useStore();
    const templates = ref([]);
    const selectedTemplate = ref(null);

    onMounted(async () => {
      const hierarchyString = router.currentRoute.value.query.hierarchy;
      console.log('Hierarchy received in UserOptionsPage:', hierarchyString);

      if (!hierarchyString) {
        console.error('No hierarchy received in route.');
        alert('No hierarchy provided. Please select a valid category.');
        router.push({ name: 'selectCategoryPage' }); // Adjust route as necessary
        return;
      }

      try {
        const response = await axios.get('/api/files/fetch-template-files', {
          params: { hierarchy: hierarchyString },
        });

        console.log('Templates response:', response.data);

        if (Array.isArray(response.data)) {
          templates.value = response.data.map((file) => ({
            label: file.filename,        // Display name in the dropdown
            filename: file.filename,     // Reference to the file
            fileId: file._id,            // Unique identifier for the file
            bucketName: file.bucketName, // Associated GridFS bucket
            contentType: file.contentType, // Optional: Useful for handling different file types
            path: file.path, // Include the path
          }));
          console.log('Templates structured:', templates.value);
        } else {
          console.error('Expected an array but got:', response.data);
          alert('Unexpected response format from the server.');
        }
      } catch (error) {
        console.error('Error fetching templates:', error);
        alert('Failed to fetch templates. Please try again later.');
      }
    });

    watch(selectedTemplate, (newValue) => {
      console.log('selectedTemplate changed to:', newValue);
      if (newValue && newValue.filename) {
        // Dispatch the filename as the dynamic title to Vuex
        store.dispatch('updateDynamicTitle', newValue.filename);
        console.log('this is the dynamic title before dispatching to vuex', newValue.filename)
      } else {
        console.warn('No filename found in the selected template.');
      }
      store.dispatch('updateDynamicInputs', []);
      store.dispatch('updateDropdownMenus', []);
      store.dispatch('setDynamicDateFields', []);
    });

    const navigateToInputFieldsPage = () => {
      if (!selectedTemplate.value) {
        alert('No template selected. Please select a template first.');
        return;
      }

      // Save the full template object in Vuex
      store.dispatch('updateSelectedTemplate', selectedTemplate.value);
      console.log('Navigating to InputFieldsPage with template metadata:', selectedTemplate.value);

      // Navigate to the InputFieldsPage.vue
      router.push({ name: 'inputFieldsPage' });
    };

    return {
      templates,
      selectedTemplate,
      navigateToInputFieldsPage,
    };
  },
});
</script>
